INSERT INTO knowledge_base (lang, lb_id, difficulty, page, title, tags, summary, content, eg_in, eg_out) VALUES 
('c++', 11, 'beginner', 1, 'C++ 变量声明', '["变量","声明"]', '介绍如何在C++中声明变量。', '在C++中，变量声明用于指定变量的类型和名称。声明变量后，可以在程序中使用它。例如，声明一个整型变量：`int age;`。\n变量声明可以位于函数内部（局部变量）或外部（全局变量），这决定了变量的作用域和生命周期。', '["int a;","double b;","char c;"]', '["声明了整型变量a","声明了双精度变量b","声明了字符变量c"]'),
('c++', 12, 'beginner', 1, 'C++ 变量初始化', '["变量","初始化"]', '学习如何在声明时初始化变量。', '变量初始化是在声明变量的同时赋予其初始值。例如，`int age = 25;` 声明并初始化了一个整型变量。初始化可以避免使用未初始化的变量，这是常见的错误来源。\nC++支持多种初始化方式，如直接初始化、拷贝初始化等。', '["int x = 10;","double pi = 3.14;","char grade = ''A'';"]', '["变量x初始化为10","变量pi初始化为3.14","变量grade初始化为''A''"]'),
('c++', 13, 'beginner', 1, 'C++ 常量定义', '["常量","const"]', '使用const关键字定义常量。', '常量是其值不可改变的变量。在C++中，使用const关键字定义常量，例如 `const int MAX_SIZE = 100;`。常量必须在定义时初始化，并且之后不能修改。\n使用常量可以提高代码的可读性和安全性。', '["const int MAX_SIZE = 100;","const double PI = 3.14159;","const char NEWLINE = ''\\n'';"]', '["常量MAX_SIZE定义为100","常量PI定义为3.14159","常量NEWLINE定义为换行符"]'),
('c++', 14, 'beginner', 1, 'C++ 常量表达式', '["常量","constexpr"]', '使用constexpr定义编译时常量。', 'constexpr用于定义在编译时已知的常量表达式。例如，`constexpr int ARRAY_SIZE = 10;`。constexpr变量必须是常量表达式，并在编译时求值。\n这有助于优化和确保常量性。', '["constexpr int ARRAY_SIZE = 10;","constexpr double E = 2.71828;","constexpr char TAB = ''\\t'';"]', '["常量表达式ARRAY_SIZE定义为10","常量表达式E定义为2.71828","常量表达式TAB定义为制表符"]'),
('c++', 15, 'beginner', 1, '变量与常量区别', '["变量","常量","比较"]', '比较变量和常量的不同。', '变量值可以改变，常量值不可改变。变量用于存储可变数据，而常量用于固定值。例如，`int var = 5;` 可以重新赋值，但 `const int con = 5;` 不能。\n常量提供代码安全性和可读性，避免意外修改。', '["int var = 5;\\nvar = 10;","const int con = 5;\\n// con = 10; // 错误","// 示例展示差异"]', '["变量var可以重新赋值为10","常量con不能重新赋值，编译错误","常量一旦定义，值不可变"]');